parameters.jsCode:
const originalInput = $('Set - Prepare Technical Context').item.json;
const current = $input.item.json;

let aiOutput =
  current.output ||
  current.text ||
  current.message ||
  current.content ||
  current.data ||
  current;

if (typeof aiOutput === 'string') {
  aiOutput = aiOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  try {
    aiOutput = JSON.parse(aiOutput);
  } catch (error) {
    aiOutput = {
      wf02_technical_breakdown: {
        architecture_summary: 'AI output could not be parsed as valid JSON.',
        dev_tasks: [],
        qa_tasks: [],
        tdd_recommendations: [],
        git_strategy: {
          suggested_branch_name: '',
          commit_guidelines: [],
          pull_request_checklist: []
        },
        ci_cd_expectations: {
          pipeline_steps: [],
          quality_gates: [],
          deployment_notes: []
        },
        suggested_files_to_change: [],
        technical_risks: ['Invalid JSON returned by the AI agent.'],
        architecture_impact: 'high',
        estimated_story_points: 0,
        ready_for_code_assistance: false,
        human_validation_required: true
      }
    };
  }
}

const breakdown = aiOutput.wf02_technical_breakdown || aiOutput;

return {
  json: {
    ...originalInput,
    wf02_technical_breakdown: {
      architecture_summary: breakdown.architecture_summary || '',
      dev_tasks: Array.isArray(breakdown.dev_tasks) ? breakdown.dev_tasks : [],
      qa_tasks: Array.isArray(breakdown.qa_tasks) ? breakdown.qa_tasks : [],
      tdd_recommendations: Array.isArray(breakdown.tdd_recommendations) ? breakdown.tdd_recommendations : [],
      git_strategy: breakdown.git_strategy || {
        suggested_branch_name: '',
        commit_guidelines: [],
        pull_request_checklist: []
      },
      ci_cd_expectations: breakdown.ci_cd_expectations || {
        pipeline_steps: [],
        quality_gates: [],
        deployment_notes: []
      },
      suggested_files_to_change: Array.isArray(breakdown.suggested_files_to_change) ? breakdown.suggested_files_to_change : [],
      technical_risks: Array.isArray(breakdown.technical_risks) ? breakdown.technical_risks : [],
      architecture_impact: breakdown.architecture_impact || 'medium',
      estimated_story_points: Number(breakdown.estimated_story_points || 0),
      ready_for_code_assistance: Boolean(breakdown.ready_for_code_assistance),
      human_validation_required: true
    }
  }
};
